// ============================================================
// Gera dados.json (sessões da Sofia já classificadas, sem PII)
// Publicado 1x/dia no GitHub Pages via node GitHub (edit file).
// ============================================================

const CANAL_SOFIA = "9870-0149";

function isDoCanal(title, canais) {
  const t = String(title || '');
  if (Array.isArray(canais)) return canais.some(c => t.includes(c));
  return t.includes(canais);
}
function limparSistema(content) {
  return String(content || '')
    .replace(/\[USER=\d+\s*REPLACE\]/gi, '')
    .replace(/\[\/USER\]/gi, '');
}
function foiEncerrado(msgs, resolvedBy, finishedAt) {
  const porMsg = msgs.some(m =>
    String(m.author_type || '').toLowerCase() === 'sistema' && (
      String(m.content).includes('encerrou a sessão') ||
      String(m.content).toLowerCase().includes('encerrada automaticamente')
    )
  );
  return porMsg
    || (finishedAt != null && String(finishedAt).trim() !== '')
    || String(resolvedBy || '').startsWith('encerrado_');
}
function foiTransferido(hadHuman, msgs) {
  if (String(hadHuman || '').trim() === 'Sim') return true;
  return msgs.some(m =>
    String(m.author_type || '').toLowerCase() === 'sistema' &&
    String(m.content).includes('transferiu a conversa para')
  );
}
function sofiaFoiEfetiva(msgs) {
  function isSofia(m) {
    return String(m.author_name || '').toLowerCase() === 'sofia' &&
           String(m.author_type || '').toLowerCase() !== 'sistema';
  }
  function isHumanoReal(m) {
    const nome = String(m.author_name || '').toLowerCase();
    const tipo = String(m.author_type || '').toLowerCase();
    if (nome === 'sofia' || nome === 'laura') return false;
    if (tipo === 'sistema') return false;
    if (tipo === 'humano') return true;
    if (tipo === 'ia') return false;
    if (tipo === 'cliente') return true;
    return false;
  }
  let lastIdx = -1;
  for (let i = msgs.length - 1; i >= 0; i--) {
    if (isSofia(msgs[i])) { lastIdx = i; break; }
  }
  if (lastIdx < 0) return false;
  for (let i = lastIdx + 1; i < msgs.length; i++) {
    if (isHumanoReal(msgs[i])) return false;
  }
  return true;
}

// ---- Dados recebidos dos nodes de leitura da planilha ----
const linhasAtendimentos = $('Ler planilha (atendimentos)').all().map(i => i.json);
const linhasMensagens = $('Ler planilha (mensagens)').all().map(i => i.json);

const linhasSofia = linhasAtendimentos.filter(r => isDoCanal(r.title, CANAL_SOFIA));
const sidsSofia = new Set(linhasSofia.map(r => String(r.session_id).replace(/\.0$/, '')));

const msgsPorSessao = {};
linhasMensagens.forEach(r => {
  const sid = String(r.session_id).replace(/\.0$/, '');
  if (!sidsSofia.has(sid)) return;
  if (!msgsPorSessao[sid]) msgsPorSessao[sid] = [];
  msgsPorSessao[sid].push({
    author_type: String(r.author_type || ''),
    author_name: String(r.author_name || ''),
    content: String(r.content || ''),
    sent_at: r.sent_at,
  });
});
Object.values(msgsPorSessao).forEach(msgs => msgs.sort((a, b) => new Date(a.sent_at) - new Date(b.sent_at)));

function getMsgs(sid) {
  return msgsPorSessao[String(sid).replace(/\.0$/, '')] || [];
}

// ---- Classificação por sessão (sem PII: nada de nome, telefone, texto) ----
let emAbertoAtual = 0;
const sessoes = [];

linhasSofia.forEach(r => {
  if (!r.started_at) return; // sem data de início, não dá pra bucketizar no painel
  const msgs = getMsgs(r.session_id);
  const hadHuman = String(r.had_human || '').trim();
  const finishedAt = r.finished_at;
  const resolvedBy = String(r.resolved_by || '');

  const concluido = foiEncerrado(msgs, resolvedBy, finishedAt);
  const transferido = foiTransferido(hadHuman, msgs);
  if (!concluido) emAbertoAtual++;

  let efetivo;
  if (msgs.length > 0) {
    efetivo = sofiaFoiEfetiva(msgs);
  } else {
    efetivo = hadHuman === 'Não' &&
      (resolvedBy === 'em_andamento_sofia' || resolvedBy === 'encerrado_sofia' || resolvedBy === 'ia_ou_sem_humano');
  }

  sessoes.push({
    started_at: r.started_at,
    concluido,
    transferido,
    efetivo,
  });
});

const payload = {
  canal: CANAL_SOFIA,
  sessoes,
  emAbertoAtual,
  atualizado_em: new Date().toISOString(),
};

return [{ json: { fileContent: JSON.stringify(payload) } }];
